checker_dsl:
EXISTS (`taint path TP`) {
  AND {
    EXISTS (`source node SN`) {
      AND {
        (`SN is an instance of ActiveThreatModelSource`),
        EXISTS (`sink node SK`) {
          AND {
            (`SK is an instance of SpelExpressionEvaluationSink`),
            EXISTS (`method call MC`) {
              AND {
                (`MC's method is an instance of ExpressionEvaluationMethod`),
                (`MC's qualifier equals SK as expression`),
                NOT {
                  EXISTS (`safe evaluation context flow SECF`) {
                    (`SECF flows to MC's first argument`)
                  }
                }
              }
            }
          }
        }
      }
    },
    (`TP is a data flow path from SN to SK`),
    EXISTS (`additional taint step ATS`) {
      AND {
        (`ATS is an instance of SpelExpressionInjectionAdditionalTaintStep`),
        (`ATS provides additional flow steps between nodes in TP`)
      }
    }
  }
}
